mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM user_follow uf
           JOIN users u ON u.user_id = uf.follower
    WHERE uf.follower = #{follower}
      AND uf.followee = #{followee}
      AND u.deleted_at IS NULL
)

mapper.insert:
INSERT INTO user_follow (
    follower,
    followee
) VALUES (
    #{follower},
    #{followee}
)

mapper.delete:
DELETE FROM user_follow
WHERE follower = #{follower}
  AND followee = #{followee}
